const agentOutput = $input.first().json.output || {};
const lead = $('Get Leads - Stage 2 Ready').item.json;

// Calculate initial AI score
let aiScore = 0;

if (agentOutput.company_size === 'medium' || agentOutput.company_size === 'large') aiScore += 20;
if (agentOutput.recent_activity && agentOutput.recent_activity !== 'None') aiScore += 15;
if (agentOutput.linkedin_url) aiScore += 10;
if (agentOutput.pain_points && agentOutput.pain_points.length >= 3) aiScore += 10;

return {
  lead_id: lead.id,
  products_services: agentOutput.products_services,
  target_customer: agentOutput.target_customer,
  pain_points: JSON.stringify(agentOutput.pain_points || []),
  recent_news: agentOutput.recent_activity,
  company_size: agentOutput.company_size,
  decision_maker_access: agentOutput.decision_maker,
  personalization_hook: agentOutput.personalization_hook,
  company_linkedin_url: agentOutput.linkedin_url,
  ai_research_score: aiScore,
  enrichment_stage: 2
};

